474→// MarshalJSON implements custom JSON marshaling for CallToolResult
475→func (r CallToolResult) MarshalJSON() ([]byte, error) {
476→	m := make(map[string]any)
477→
478→	// Marshal Meta if present
479→	if r.Meta != nil {
480→		m["_meta"] = r.Meta
481→	}
482→
483→	// Marshal Content array
484→	content := make([]any, len(r.Content))
485→	for i, c := range r.Content {
486→		content[i] = c
487→	}
488→	m["content"] = content
489→
490→	// Marshal StructuredContent if present
491→	if r.StructuredContent != nil {
492→		m["structuredContent"] = r.StructuredContent
493→	}
494→
495→	// Marshal IsError if true
