503→// UnmarshalJSON implements custom JSON unmarshaling for CallToolResult
504→func (r *CallToolResult) UnmarshalJSON(data []byte) error {
505→	var raw map[string]any
506→	if err := json.Unmarshal(data, &raw); err != nil {
507→		return err
508→	}
509→
510→	// Unmarshal Meta
511→	if meta, ok := raw["_meta"]; ok {
512→		if metaMap, ok := meta.(map[string]any); ok {
513→			r.Meta = NewMetaFromMap(metaMap)
514→		}
515→	}
516→
517→	// Unmarshal Content array
518→	if contentRaw, ok := raw["content"]; ok {
519→		if contentArray, ok := contentRaw.([]any); ok {
520→			r.Content = make([]Content, len(contentArray))
521→			for i, item := range contentArray {
522→				itemBytes, err := json.Marshal(item)
523→				if err != nil {
524→					return err
525→				}
526→				content, err := UnmarshalContent(itemBytes)
527→				if err != nil {
528→					return err
529→				}
530→				r.Content[i] = content
531→			}
532→		}
533→	}
534→
535→	// Unmarshal StructuredContent if present
536→	if structured, ok := raw["structuredContent"]; ok {
537→		r.StructuredContent = structured
538→	}
539→
540→	// Unmarshal IsError
541→	if isError, ok := raw["isError"]; ok {
542→		if isErrorBool, ok := isError.(bool); ok {
543→			r.IsError = isErrorBool
544→		}
545→	}
546→
547→	return nil
548→}
