606→// MarshalJSON implements the json.Marshaler interface for Tool.
607→// It handles marshaling either InputSchema or RawInputSchema based on which is set.
608→func (t Tool) MarshalJSON() ([]byte, error) {
609→	// Create a map to build the JSON structure
610→	m := make(map[string]any, 5)
611→
612→	// Add the name and description
613→	m["name"] = t.Name
614→	if t.Description != "" {
615→		m["description"] = t.Description
616→	}
617→
618→	// Determine which input schema to use
619→	if t.RawInputSchema != nil {
620→		if t.InputSchema.Type != "" {
621→			return nil, fmt.Errorf("tool %s has both InputSchema and RawInputSchema set: %w", t.Name, errToolSchemaConflict)
622→		}
623→		m["inputSchema"] = t.RawInputSchema
624→	} else {
625→		// Use the structured InputSchema
626→		m["inputSchema"] = t.InputSchema
627→	}
628→
629→	// Add output schema if present
630→	if t.RawOutputSchema != nil {
631→		if t.OutputSchema.Type != "" {
632→			return nil, fmt.Errorf("tool %s has both OutputSchema and RawOutputSchema set: %w", t.Name, errToolSchemaConflict)
633→		}
634→		m["outputSchema"] = t.RawOutputSchema
635→	} else if t.OutputSchema.Type != "" { // If no output schema is specified, do not return anything
636→		m["outputSchema"] = t.OutputSchema
637→	}
638→
639→	m["annotations"] = t.Annotations
640→
641→	if t.DeferLoading {
642→		m["defer_loading"] = t.DeferLoading
643→	}
644→
645→	// Marshal Meta if present
646→	if t.Meta != nil {
647→		m["_meta"] = t.Meta
648→	}
649→
650→	if t.Icons != nil {
651→		m["icons"] = t.Icons
652→	}
653→
654→	if t.Execution != nil {
655→		m["execution"] = t.Execution
